<?php
namespace App\Domain\Equipment;
use App\Domain\Equipment\Data\EquipmentEligibilityResult;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use InvalidArgumentException;
final class EquipmentEligibilityService{private $items;public function __construct(EquippableItemValidator $items){$this->items=$items;}public function evaluate(Character $character,ItemInstance $instance,Item $item,$slot,$allowedClasses=null,$characterClass=null){$reasons=[];$owned=(int)$instance->character_id===(int)$character->id;if(!$owned)$reasons[]='instance_not_owned';if(!in_array($instance->status,[ItemInstanceStatus::AVAILABLE,ItemInstanceStatus::EQUIPPED],true))$reasons[]='invalid_instance_status';if($item->status!==CatalogStatus::ACTIVE)$reasons[]='item_inactive';try{$type=$this->items->equipmentType($item);if($type===null)$reasons[]='item_not_equippable';elseif(CharacterEquipmentSlot::equipmentType($slot)!==$type)$reasons[]='slot_incompatible';}catch(InvalidArgumentException $e){$reasons[]='item_not_equippable';}$required=max(1,(int)$item->required_level);$level=(int)$character->level;$levelMet=$level>=$required;if(!$levelMet)$reasons[]='level_requirement_not_met';$classes=$allowedClasses===null?$item->allowedCharacterClasses()->orderBy('character_classes.id')->get():$allowedClasses;$current=$characterClass===null?$character->characterClass:$characterClass;$classMet=$classes->isEmpty()||($current&&$classes->contains(function($class)use($current){return(int)$class->id===(int)$current->id;}));if(!$classMet)$reasons[]='class_requirement_not_met';$allowed=$classes->map(function($class){return['id'=>(int)$class->id,'code'=>$class->code,'name'=>$class->name,'status'=>$class->status];})->values()->all();$missing=max(0,$required-$level);$message='Requisitos cumplidos.';if(!$levelMet)$message='Te faltan '.$missing.' '.($missing===1?'nivel':'niveles').' para equipar este objeto.';elseif(!$classMet)$message='Tu clase actual no puede equipar este objeto.';elseif($reasons)$message='Este objeto no puede equiparse: '.implode(', ',$reasons).'.';return new EquipmentEligibilityResult(['eligible'=>empty($reasons),'required_level'=>$required,'character_level'=>$level,'missing_levels'=>$missing,'level_requirement_met'=>$levelMet,'character_class_id'=>$current?(int)$current->id:null,'character_class_code'=>$current?$current->code:null,'character_class_name'=>$current?$current->name:null,'allowed_classes'=>$allowed,'class_requirement_met'=>$classMet,'reason_codes'=>array_values(array_unique($reasons)),'message'=>$message]);}}
